```class Solution {
public:
    int getMinSwaps(string num, int k) {
        int n = num.size();
        vector<int> count(10, 0);
        for (char c : num) {
            count[c - '0']++;
        }
        int res = 0, i = 0;
        while (k > 0) {
            if (count[9] > 0) {
                count[9]--;
                k--;
                res++;
            } else {
                while (i < n && count[i] == 0) i++;
                if (i == n) break;
                count[i]--;
                k--;
                res++;
                i++;
            }
        }
        return res;
    }
};```
